class Rectangle {
private:
 int width, height;
public:
 Rectangle(int w, int h) : width(w), height(h) {}
 int area() { return width * height; }
};

int main() {
 Rectangle obj(10, 5);
 Rectangle *ptr = &obj; // Pointer to object

 // Access members using arrow operator
 cout << "Area: " << ptr->area() << endl;

 // Alternative: dereference then dot
 cout << "Area: " << (*ptr).area() << endl;

 return 0;
}

class Student {
private:
 char *name;
 int marks;
public:
 Student(const char *n, int m) {
 name = new char[strlen(n) + 1];
 strcpy(name, n);
 marks = m;
 }
 ~Student() {
 delete[] name; // Destructor frees dynamic memory
 cout << "Destructor called" << endl;
 }
 void display() {
 cout << "Name: " << name << ", Marks: " << marks << endl;
 }
};

int main() {
 Student *ptr = new Student("John", 85); // Dynamic allocation
 ptr->display(); // Access through pointer
 delete ptr; // Explicit deallocation, calls destructor
 ptr = nullptr; // Avoid dangling pointer
 return 0;
}

class Box {
private:
 int width, height;
public:
 Box(int width, int height) {
 // 'this' distinguishes parameter from member
 this->width = width;
 this->height = height;
 }

 Box* compare(Box &other) {
 // Returns pointer to larger Box
 if (this->area() > other.area())
 return this; // Return current object address
 else
 return &other; // Return address of other object
 }

 int area() { return width * height; }
};

int main() {
 Box b1(10, 5), b2(6, 8);
 Box *larger = b1.compare(b2);
 cout << "Larger box area: " << larger->area() << endl;
 return 0;
}

class Shape {
public:
 virtual void draw() {
 cout << "Drawing Shape" << endl;
 }
 virtual ~Shape() {} // Virtual destructor for proper cleanup
};

class Circle : public Shape {
public:
 void draw() override {
 cout << "Drawing Circle" << endl;
 }
};

class Rectangle : public Shape {
public:
 void draw() override {
 cout << "Drawing Rectangle" << endl;
 }
};

int main() {
 Shape *shapes[3];
 shapes[0] = new Circle();
 shapes[1] = new Rectangle();
 shapes[2] = new Circle();

 for (int i = 0; i < 3; i++) {
 shapes[i]->draw(); // Runtime polymorphism
 }

 for (int i = 0; i < 3; i++) {
 delete shapes[i]; // Virtual destructor ensures proper cleanup
 }

 return 0;
}

class Employee {
private:
 int id;
 char name[20];
public:
 Employee(int i, const char *n) {
 id = i;
 strcpy(name, n);
 }
 void display() {
 cout << "ID: " << id << ", Name: " << name << endl;
 }
};

int main() {
 // Array of pointers to objects
 Employee *emp[3];

 // Create objects dynamically and store addresses
 emp[0] = new Employee(101, "Alice");
 emp[1] = new Employee(102, "Bob");
 emp[2] = new Employee(103, "Charlie");

 // Access using arrow operator
 for (int i = 0; i < 3; i++) {
 emp[i]->display();
 }

 // Free memory
 for (int i = 0; i < 3; i++) {
 delete emp[i];
 }

 return 0;
}
